1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>ORION — Supplier Status Report | June 18, 2026</title>
7	<style>
8	  * { box-sizing: border-box; margin: 0; padding: 0; }
9	  body { font-family: 'Segoe UI', Arial, sans-serif; background: #f4f6f9; color: #1a1a2e; }
10	  .container { max-width: 960px; margin: 32px auto; padding: 0 24px 48px; }
11	
12	  .header { background: linear-gradient(135deg, #00509e, #003f7f); color: white; border-radius: 10px 10px 0 0; padding: 28px 32px; }
13	  .header h1 { font-size: 22px; font-weight: 700; letter-spacing: 0.5px; }
14	  .header .subtitle { font-size: 13px; margin-top: 6px; opacity: 0.85; }
15	  .header .date { font-size: 13px; margin-top: 4px; opacity: 0.7; }
16	
17	  .card { background: white; border-radius: 0 0 10px 10px; padding: 28px 32px; margin-bottom: 20px; box-shadow: 0 2px 8px rgba(0,0,0,0.07); }
18	  .card + .card { border-radius: 10px; margin-top: 0; }
19	  .section-title { font-size: 13px; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; color: #00509e; border-bottom: 2px solid #e8edf4; padding-bottom: 8px; margin-bottom: 16px; }
20	
21	  table { width: 100%; border-collapse: collapse; font-size: 13px; }
22	  th { background: #f0f4fa; color: #003f7f; font-weight: 700; text-align: left; padding: 10px 12px; font-size: 12px; text-transform: uppercase; letter-spacing: 0.5px; }
23	  td { padding: 10px 12px; border-bottom: 1px solid #f0f3f8; vertical-align: middle; }
24	  tr:last-child td { border-bottom: none; }
25	  tr.out td { opacity: 0.5; text-decoration: line-through; }
26	  tr.out td .badge { text-decoration: none; }
27	
28	  .badge { display: inline-block; padding: 3px 9px; border-radius: 20px; font-size: 11px; font-weight: 600; white-space: nowrap; }
29	  .badge-waiting { background: #fff3cd; color: #856404; }
30	  .badge-soon { background: #d1e7dd; color: #0a5c35; }
31	  .badge-out { background: #f8d7da; color: #842029; }
32	
33	  .person-block { margin-bottom: 22px; }
34	  .person-name { font-size: 14px; font-weight: 700; color: #003f7f; margin-bottom: 10px; display: flex; align-items: center; gap: 8px; }
35	  .person-name .avatar { width: 28px; height: 28px; border-radius: 50%; background: #00509e; color: white; font-size: 11px; font-weight: 700; display: inline-flex; align-items: center; justify-content: center; }
36	  .action-list { list-style: none; }
37	  .action-list li { display: flex; align-items: flex-start; gap: 10px; padding: 8px 0; border-bottom: 1px solid #f0f3f8; font-size: 13px; }
38	  .action-list li:last-child { border-bottom: none; }
39	  .checkbox { width: 16px; height: 16px; border: 2px solid #c0cfe0; border-radius: 3px; flex-shrink: 0; margin-top: 1px; }
40	  .action-text strong { color: #1a1a2e; }
41	  .supplier-tag { display: inline-block; background: #e8edf4; color: #003f7f; border-radius: 4px; padding: 1px 7px; font-size: 11px; font-weight: 600; margin-left: 4px; }
42	  .urgent { color: #dc3545; font-size: 11px; font-weight: 700; margin-left: 6px; }
43	
44	  .timeline { display: flex; gap: 0; }
45	  .tl-item { flex: 1; text-align: center; position: relative; }
46	  .tl-item::before { content: ''; display: block; height: 3px; background: #d0dcea; position: absolute; top: 14px; left: 50%; right: -50%; z-index: 0; }
47	  .tl-item:last-child::before { display: none; }
48	  .tl-dot { width: 28px; height: 28px; border-radius: 50%; background: #00509e; color: white; font-size: 11px; font-weight: 700; display: inline-flex; align-items: center; justify-content: center; position: relative; z-index: 1; }
49	  .tl-dot.done { background: #198754; }
50	  .tl-dot.upcoming { background: #f0a500; }
51	  .tl-label { font-size: 11px; font-weight: 700; color: #003f7f; margin-top: 8px; }
52	  .tl-date { font-size: 11px; color: #6c757d; margin-top: 2px; }
53	
54	  .footer { text-align: center; font-size: 12px; color: #8899aa; margin-top: 24px; }
55	</style>
56	</head>
